import React from 'react'
import AllCompo from '../components/AllCompo';
import Footer from '../components/Footer';
import { CartProvider } from 'react-use-cart';

function page () {
    return(
        <div> 
           <AllCompo/> 
           <Footer  />
        </div>
    )
}

function AllProduct() {
  return (
    <CartProvider>
        <Page/> 
    </CartProvider>
  )
}

export default AllProduct ;
